1	import { Redirect, Slot } from 'expo-router';
2	import { useAuth } from '@/lib/auth';
3	
4	// (auth) group wraps the pre-signin screens. Authed users are bounced back to
5	// the role-appropriate tab group — keeps deep-links from leaving a signed-in
6	// user stuck on the role picker. US-032 fleshes out the role picker; US-033/034
7	// add the signup screens that will nest under this layout.
8	export default function AuthLayout() {
9	  const { role } = useAuth();
10	
11	  if (role === 'creator') return <Redirect href="/(creator)/feed" />;
12	  if (role === 'lister') return <Redirect href="/(lister)/dashboard" />;
13	
14	  return <Slot />;
15	}
