236	  // 3. JWT signed with wrong secret
237	  {
238	    const badJwt = await signMarketifyJwt(
239	      { sub: SEED_CREATOR_USER_ID, role: "creator", session_id: crypto.randomUUID() },
240	      "wrong-secret-" + Math.random().toString(36).slice(2),
241	    );
242	    const r = await post(
243	      { social_link_id: SEED_TIKTOK_SOCIAL_LINK_ID },
244	      `Bearer ${badJwt}`,
245	    );
246	    expect(
247	      "wrong-secret JWT → 401 UNAUTHORIZED",
248	      r.status === 401 && r.data?.error === "UNAUTHORIZED",
249	      r,
250	    );
251	  }
252	
253	  if (jwtSecret) {
254	    // 4. Lister-role JWT (valid signature, wrong role)
255	    {
256	      const listerJwt = await signMarketifyJwt(
257	        { sub: crypto.randomUUID(), role: "lister", session_id: crypto.randomUUID() },
258	        jwtSecret,
259	      );
260	      const r = await post(
261	        { social_link_id: SEED_TIKTOK_SOCIAL_LINK_ID },
262	        `Bearer ${listerJwt}`,
263	      );
264	      expect(
265	        "lister-role JWT → 403 FORBIDDEN",
266	        r.status === 403 && r.data?.error === "FORBIDDEN",
267	        r,
268	      );
269	    }
270	
271	    // Creator JWT — reused for the remaining validation paths.
272	    const creatorJwt = await signMarketifyJwt(
273	      {
274	        sub: SEED_CREATOR_USER_ID,
275	        role: "creator",
276	        session_id: crypto.randomUUID(),
277	      },
278	      jwtSecret,
279	    );
280	    const creatorAuth = `Bearer ${creatorJwt}`;
281	
282	    // 5. Malformed JSON body
283	    {
284	      const r = await post("{not-json", creatorAuth);
285	      expect(
286	        "malformed JSON → 400 INVALID_JSON",
287	        r.status === 400 && r.data?.error === "INVALID_JSON",
288	        r,
289	      );
290	    }
291	
292	    // 6. Missing social_link_id
293	    {
294	      const r = await post({}, creatorAuth);
295	      expect(
296	        "missing social_link_id → 400 INVALID_REQUEST",
297	        r.status === 400 && r.data?.error === "INVALID_REQUEST",
298	        r,
299	      );
300	    }
301	
302	    // 7. Non-UUID social_link_id
303	    {
304	      const r = await post({ social_link_id: "not-a-uuid" }, creatorAuth);
305	      expect(
306	        "non-UUID social_link_id → 400 INVALID_REQUEST",
307	        r.status === 400 && r.data?.error === "INVALID_REQUEST",
308	        r,
309	      );
310	    }
311	
312	    // 8. Valid UUID that either doesn't exist or isn't owned by caller.
313	    //    Both cases collapse to 404 LINK_NOT_FOUND so the endpoint doesn't
314	    //    leak id existence across creators.
315	    {
316	      const r = await post(
317	        { social_link_id: "00000000-0000-0000-0000-000000000000" },
318	        creatorAuth,
319	      );
320	      expect(
321	        "unknown social_link_id → 404 LINK_NOT_FOUND",
322	        r.status === 404 && r.data?.error === "LINK_NOT_FOUND",
323	        r,
324	      );
325	    }
326	
327	    if (serviceRoleKey) {
328	      // 9. Throttle: bump last_scrape_attempt_at to now and expect 429.
329	      //    This verifies that the 6h window is honoured without burning Apify.
330	      {
331	        const nowIso = new Date().toISOString();
332	        await setLinkFields(SEED_TIKTOK_SOCIAL_LINK_ID, {
333	          last_scrape_attempt_at: nowIso,
334	        });
335	        const r = await post(
336	          { social_link_id: SEED_TIKTOK_SOCIAL_LINK_ID },
337	          creatorAuth,
338	        );
339	        const retryAfter = r.data?.retry_after_sec;
340	        expect(
341	          "recent attempt → 429 RATE_LIMIT with retry_after_sec",
342	          r.status === 429 &&
343	            r.data?.error === "RATE_LIMIT" &&
344	            typeof retryAfter === "number" &&
345	            retryAfter > 0 &&
346	            retryAfter <= 6 * 60 * 60,
347	          r,
348	        );
349	      }
350	
351	      // 10. LINK_UNLINKED: flip status to 'unlinked' and confirm 422.
352	      //     Restore the linked state immediately after — the finally block
353	      //     will also re-apply the original snapshot, but doing it inline
354	      //     keeps the row consistent if later assertions are added.
355	      {
356	        await setLinkFields(SEED_TIKTOK_SOCIAL_LINK_ID, { status: "unlinked" });
357	        const r = await post(
358	          { social_link_id: SEED_TIKTOK_SOCIAL_LINK_ID },
359	          creatorAuth,
360	        );
361	        expect(
362	          "status=unlinked → 422 LINK_UNLINKED",
363	          r.status === 422 && r.data?.error === "LINK_UNLINKED",
364	          r,
365	        );
366	        await setLinkFields(SEED_TIKTOK_SOCIAL_LINK_ID, { status: "linked" });
367	      }
368	
369	      // 11. already_fresh: insert a synthetic `is_latest=true, status='fresh'`
370	      //     snapshot for the required scrape_mode and clear the throttle so
371	      //     the endpoint has to reach the already_fresh branch. The function
372	      //     should return 200 { status: 'already_fresh' } with snapshot_ids
373	      //     containing the row we just wrote.
374	      {
375	        await setLinkFields(SEED_TIKTOK_SOCIAL_LINK_ID, {
376	          last_scrape_attempt_at: null,
377	        });
378	        const insertRes = await fetch(
379	          `${supabaseUrl}/rest/v1/metric_snapshots`,
380	          {
381	            method: "POST",
382	            headers: {
383	              apikey: serviceRoleKey!,
384	              Authorization: `Bearer ${serviceRoleKey}`,
385	              "Content-Type": "application/json",
386	              Prefer: "return=representation",
387	            },
388	            body: JSON.stringify({
389	              social_link_id: SEED_TIKTOK_SOCIAL_LINK_ID,
390	              scrape_mode: "tiktok_profile",
391	              apify_run_id: `us021_fresh_${Date.now()}`,
392	              status: "fresh",
393	              is_latest: true,
394	              fetched_at: new Date().toISOString(),
395	              follower_count: 100,
396	              following_count: 10,
397	              total_likes: 500,
398	              video_count: 5,
399	            }),
400	          },
401	        );
402	        if (!insertRes.ok) {
403	          console.error(
404	            "fresh snapshot insert failed (test 11 skipped):",
405	            insertRes.status,
406	            await insertRes.text(),
407	          );
408	        } else {
409	          const [inserted] = (await insertRes.json()) as Array<{ id: string }>;
410	          insertedSnapshotIds.push(inserted.id);
411	          const r = await post(
412	            { social_link_id: SEED_TIKTOK_SOCIAL_LINK_ID },
413	            creatorAuth,
414	          );
415	          expect(
416	            "fresh snapshot within window → 200 already_fresh",
417	            r.status === 200 &&
418	              r.data?.status === "already_fresh" &&
419	              Array.isArray(r.data?.snapshot_ids) &&
420	              r.data.snapshot_ids.includes(inserted.id) &&
421	              r.data?.metrics_status?.tiktok === "fresh",
422	            r,
423	          );
424	        }
425	      }
426	    }
427	  }
428	
429	  console.log("all metrics-refresh smoke tests passed");
430	} finally {
431	  await restore();
432	}
