1	// US-036 backend probe: signs up a creator (exercising real JWT mint via
2	// auth-signup-creator), then calls metrics-refresh with the returned JWT —
3	// the exact backend path the pull-to-refresh gesture triggers.
4	//
5	// Exists because mobile-mcp's swipe-down injection on iOS 26.3 simulator is
6	// intercepted by the iOS system home-gesture before the app's Gesture.Pan
7	// can register. The UI gesture code is complete + typed + linted; this
8	// probe verifies the full authed refresh call works end-to-end.
9	//
10	// Usage: bun run scripts/test/probe-us036-refresh.ts
11	
12	const supabaseUrl = process.env.SUPABASE_URL;
13	const anonKey = process.env.SUPABASE_ANON_KEY;
14	if (!supabaseUrl || !anonKey) {
15	  console.error("SUPABASE_URL and SUPABASE_ANON_KEY are required in .env");
16	  process.exit(1);
17	}
18	
19	const unique = Date.now();
20	const signupRes = await fetch(
21	  `${supabaseUrl}/functions/v1/auth-signup-creator`,
22	  {
23	    method: "POST",
24	    headers: {
25	      "Content-Type": "application/json",
26	      Authorization: `Bearer ${anonKey}`,
27	      apikey: anonKey,
28	    },
29	    body: JSON.stringify({
30	      username: `us036_probe_${unique}`,
31	      tiktok_handle: `us036_probe_${unique}`,
32	    }),
33	  },
34	);
35	const signupBody = (await signupRes.json().catch(() => null)) as {
36	  token?: string;
37	  user_id?: string;
38	} | null;
39	console.log("[signup]", signupRes.status);
40	if (signupRes.status !== 200 || !signupBody?.token || !signupBody?.user_id) {
41	  console.error("[signup] unexpected", signupBody);
42	  process.exit(1);
43	}
44	
45	// Look up the freshly created tiktok social_link via PostgREST using the JWT —
46	// this doubles as the JWT/PostgREST drift check.
47	const linksRes = await fetch(
48	  `${supabaseUrl}/rest/v1/social_links?user_id=eq.${signupBody.user_id}&platform=eq.tiktok&select=id`,
49	  {
50	    headers: { apikey: anonKey, Authorization: `Bearer ${signupBody.token}` },
51	  },
52	);
53	console.log("[postgrest social_links]", linksRes.status);
54	if (linksRes.status !== 200) {
55	  console.error("[postgrest]", await linksRes.text());
56	  process.exit(1);
57	}
58	const linkRows = (await linksRes.json()) as Array<{ id: string }>;
59	const socialLinkId = linkRows[0]?.id;
60	if (!socialLinkId) {
61	  console.error("[postgrest] no tiktok social_link row found");
62	  process.exit(1);
63	}
64	
65	const refreshRes = await fetch(
66	  `${supabaseUrl}/functions/v1/metrics-refresh`,
67	  {
68	    method: "POST",
69	    headers: {
70	      "Content-Type": "application/json",
71	      Authorization: `Bearer ${signupBody.token}`,
72	      apikey: anonKey,
73	    },
74	    body: JSON.stringify({ social_link_id: socialLinkId }),
75	  },
76	);
77	const refreshBody = await refreshRes.text();
78	console.log("[metrics-refresh]", refreshRes.status, refreshBody.slice(0, 400));
79	
80	if (refreshRes.status !== 200) {
81	  console.error("[verdict] refresh path BROKEN");
82	  process.exit(2);
83	}
84	console.log(
85	  "[verdict] US-036 backend path VERIFIED — signup JWT accepted by PostgREST + metrics-refresh",
86	);
